/**
 * The A7 failure→code table (attestation-evidence.md §1). Mirrors the Swift `VerdictReason`.
 */

public enum VerdictReason {
    
    case ok
    case quoteSigInvalid
    case tcbOutOfDate
    case collateralStale
    case measurementUnpinned
    case composeMismatch
    case appIdMismatch
    case bindingMismatch
    case noLogAbsent
    case regimeUnsupported
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeVerdictReason: FfiConverterRustBuffer {
    typealias SwiftType = VerdictReason

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> VerdictReason {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .ok
        
        case 2: return .quoteSigInvalid
        
        case 3: return .tcbOutOfDate
        
        case 4: return .collateralStale
        
        case 5: return .measurementUnpinned
        
        case 6: return .composeMismatch
        
        case 7: return .appIdMismatch
        
        case 8: return .bindingMismatch
        
        case 9: return .noLogAbsent
        
        case 10: return .regimeUnsupported
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: VerdictReason, into buf: inout [UInt8]) {
        switch value {
        
        
        case .ok:
            writeInt(&buf, Int32(1))
        
        
        case .quoteSigInvalid:
            writeInt(&buf, Int32(2))
        
        
        case .tcbOutOfDate:
            writeInt(&buf, Int32(3))
        
        
        case .collateralStale:
            writeInt(&buf, Int32(4))
        
        
        case .measurementUnpinned:
            writeInt(&buf, Int32(5))
        
        
        case .composeMismatch:
            writeInt(&buf, Int32(6))
        
        
        case .appIdMismatch:
            writeInt(&buf, Int32(7))
        
        
        case .bindingMismatch:
            writeInt(&buf, Int32(8))
        
        
        case .noLogAbsent:
            writeInt(&buf, Int32(9))
        
        
        case .regimeUnsupported:
            writeInt(&buf, Int32(10))
        
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeVerdictReason_lift(_ buf: RustBuffer) throws -> VerdictReason {
    return try FfiConverterTypeVerdictReason.lift(buf)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeVerdictReason_lower(_ value: VerdictReason) -> RustBuffer {
    return FfiConverterTypeVerdictReason.lower(value)
}



extension VerdictReason: Equatable, Hashable {}



#if swift(>=5.8)
@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterSequenceString: FfiConverterRustBuffer {
    typealias SwiftType = [String]

    public static func write(_ value: [String], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterString.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [String] {
        let len: Int32 = try readInt(&buf)
        var seq = [String]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterString.read(from: &buf))
        }
        return seq
    }
}
