private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private var initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 26
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_caladon_core_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_caladon_core_checksum_func_challenge_hex() != 645) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_derive_session_key() != 40015) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_open_chat() != 63627) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_open_wmk() != 12181) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_pad() != 56056) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_passkey_derive_wrapping_key() != 44151) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_passkey_unwrap_seed() != 17782) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_passkey_wrap_seed() != 48547) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_seal_chat() != 32439) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_seal_wmk() != 62818) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_seed_decode() != 33732) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_seed_encode() != 31996) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_unpad() != 5473) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_verify_quote() != 62102) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_caladon_core_checksum_func_x25519_public() != 44449) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

private func uniffiEnsureInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

